def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            base = (1 - ratio)**4 * 20
            oscillation = 0
            for x in range(1, 6):
                oscillation += np.cos(ratio * x * np.pi * 2) * (5 / x)
            score += base + oscillation
            if capacity % 2 == 0:
                score += np.sqrt(capacity) * 1.5
        elif 0.2 <= ratio < 0.5:
            score += np.log1p(ratio*10) * 12
            product = 1
            for a in range(1, int(capacity) + 1):
                if a % 3 == 0 and a <= item:
                    product *= 1.01
                elif a % 5 == 0:
                    product *= 0.99
            score *= product
            for y in range(1, 4):
                score += ((-1)**y) * np.sin(ratio * y * np.pi) * 4
        elif 0.5 <= ratio <= 0.85:
            sigmoid = 1 / (1 + np.exp(-15 * (ratio - 0.65)))
            score += sigmoid * 25
            divisors_sum = 0
            for d in range(1, int(capacity // 2) + 1):
                if capacity % d == 0:
                    if d < item:
                        divisors_sum += d * 0.3
                    else:
                        divisors_sum -= d * 0.1
            score += divisors_sum
            harmonic = 0
            for n in range(1, 6):
                harmonic += 1 / n
            score += harmonic * (1 - ratio)
        elif 0.85 < ratio <= 1.2:
            exp_decay = np.exp(-5 * (ratio - 0.85))
            score += (1 - exp_decay) * 30
            for p in range(1, 8):
                score += (p % 2) * (np.sin(p * ratio * np.pi / 2)) * 2.5
            count_divisible = 0
            for q in range(1, int(capacity) + 1):
                if (q * ratio) % 1 < 0.05:
                    count_divisible += 1
            score += count_divisible * 1.2
        else:
            penalty = 0
            int_ratio = int(ratio)
            for k in range(1, int_ratio + 2):
                if k != 0 and abs((ratio % k) - 0) < 1e-4:
                    penalty += k * 3
            remainder_sum = 0
            for r in range(1, 6):
                remainder_sum += ((ratio * r) % 1) * 4
            score = penalty + remainder_sum + (ratio - 1.2) * 40
            if ratio > 3:
                for s in range(1, int(capacity // 3) + 1):
                    if capacity % s == 0 and s % 3 == 0:
                        score += np.log1p(s) * 0.8
            if int(capacity) % 7 == 0:
                score *= 1.25
            if int(capacity) % 11 == 0 and ratio > 2:
                score *= 0.85
        if ratio > 0.4 and ratio < 0.9:
            for t in range(1, 5):
                if (int(capacity) + t) % 4 == 0:
                    score += np.exp(-t) * 3
        if capacity > 50 and ratio < 0.6:
            for u in range(1, 3):
                score += np.tanh(ratio * u) * 7
        priorities[i] = score
    finite_mask = np.isfinite(priorities)
    if not np.any(finite_mask):
        return priorities
    min_priority = np.min(priorities[finite_mask])
    priorities = np.where(finite_mask, priorities, min_priority + 250)
    return priorities
